import { animated, useTransition, UseTransitionProps } from '@react-spring/web';
import * as React from 'react';

import { extent } from 'd3-array';

import { AxisBottom, AxisLeft } from '@visx/axis';
import { RectClipPath } from '@visx/clip-path';
import { localPoint } from '@visx/event';
import { ParentSize } from '@visx/responsive';
import { scaleLinear, scaleUtc } from '@visx/scale';
import { Zoom } from '@visx/zoom';

// import { TransformMatrix } from '@visx/zoom/lib/types';
import { useBlogPostContext } from '../../../components/BlogPostContext';

type Item = {
  date: string;
  close: number;
  lower: number;
  middle: number;
  upper: number;
};

type Props = {
  width: number;
  height: number;
  data: Item[];
};

const MARGIN = {
  top: 20,
  left: 40,
  right: 20,
  bottom: 40,
};

// const INITIAL_TRANSFORM: TransformMatrix = {
//   scaleX: 1.27,
//   scaleY: 1.27,
//   translateX: -211.62,
//   translateY: 162.59,
//   skewX: 0,
//   skewY: 0,
// };

const Content = React.memo((props: Props) => {
  const { width, height, data } = props;

  const scaleX = React.useMemo(
    () =>
      scaleUtc({
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        domain: extent(data, (d) => new Date(d.date)) as any,
        range: [MARGIN.left, width - MARGIN.right],
      }),
    [width, data]
  );

  const scaleY = React.useMemo(
    () =>
      scaleLinear({
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        domain: extent(data, (d) => d.close) as any,
        range: [height - MARGIN.bottom, MARGIN.top],
        nice: true,
      }),
    [height, data]
  );

  const transitionParams = React.useMemo<UseTransitionProps>(
    () => ({
      from: { opacity: 0 },
      enter: { opacity: 1 },
      // delay: 200,
      trail: 1,
    }),
    [data]
  );

  const transition = useTransition(data, transitionParams);

  // eslint-disable-next-line no-console
  console.log('Content');
  return (
    <>
      <Zoom<SVGSVGElement>
        width={width}
        height={height}
        // scaleXMin={1 / 2}
        // scaleXMax={4}
        // scaleYMin={1 / 2}
        // scaleYMax={4}
        // initialTransformMatrix={INITIAL_TRANSFORM}
      >
        {(zoom) => (
          <div style={{ position: 'relative' }}>
            <svg
              ref={zoom.containerRef}
              width={width}
              height={height}
              style={{
                cursor: zoom.isDragging ? 'grabbing' : 'grab',
                touchAction: 'none',
              }}
              onDoubleClick={(evt) => {
                const point = localPoint(evt) || { x: 0, y: 0 };
                zoom.scale({ scaleX: 2, scaleY: 2, point });
              }}
            >
              <RectClipPath id="zoom-clip" width={width} height={height} />
              <g transform={zoom.toString()}>
                <g>
                  {transition((style, { date, close }) => (
                    <animated.circle
                      key={date}
                      style={style}
                      cx={scaleX(new Date(date))}
                      cy={scaleY(close)}
                      r={1}
                      fill="blue"
                    />
                  ))}
                </g>
                <AxisLeft scale={scaleY} left={MARGIN.left} />
                <AxisBottom scale={scaleX} top={height - MARGIN.bottom} />
              </g>
              {/* <rect
              width={width}
              height={height}
              rx={14}
              fill="transparent"
              onTouchStart={dragStart}
              onTouchMove={dragMove}
              onTouchEnd={dragEnd}
              onMouseDown={dragStart}
              onMouseMove={dragMove}
              onMouseUp={dragEnd}
              onMouseLeave={() => isDragging && dragEnd()}
              onDoubleClick={(evt) => {
                const point = localPoint(evt) || { x: 0, y: 0 };
                scale({ scaleX: 2, scaleY: 2, point });
              }}
            /> */}
              {/* <g
              clipPath="url(#zoom-clip)"
              transform={`
                    scale(0.25)
                    translate(${width * 4 - width - 60}, ${
                height * 4 - height - 60
              })
                  `}
            >
              <rect width={width} height={height} fill="#1a1a1a" />
              {data.map(({ date, close }) => (
                <circle
                  key={date}
                  cx={scaleX(new Date(date))}
                  cy={scaleY(close)}
                  r={1}
                  fill="white"
                />
              ))}
              <rect
                width={width}
                height={height}
                fill="white"
                fillOpacity={0.2}
                stroke="white"
                strokeWidth={4}
                transform={toStringInvert()}
              />
            </g> */}
            </svg>
          </div>
        )}
      </Zoom>
    </>
  );
});

const Chart = React.memo(() => {
  const { data } = useBlogPostContext();
  return (
    <ParentSize debounceTime={300} enableDebounceLeadingCall={false}>
      {({ width }) => <Content width={width} height={300} data={data} />}
    </ParentSize>
  );
});

export default Chart;
